const body = $json.body || {};
return [{ json: {
  titulo:     body.titulo     || 'Não informado',
  problema:   body.problema   || body.descricao || 'Não informado',
  descricao:  body.descricao  || '',
  user:       body.user       || '',
  parecer_id: body.parecer_id || ''
}}];

var r = $input.first().json;
var txt = r.text || r.output || (r.content && r.content[0] && r.content[0].text) || JSON.stringify(r);

var q = { termos: [], query_ilike: 'contrato', confidence: 0.5, domain: '' };
var s = txt.indexOf('{'); var e = txt.lastIndexOf('}');
if (s > -1 && e > s) { try { q = JSON.parse(txt.slice(s, e+1)); } catch(err) {} }

// Remove aspas ou apóstrofos que a IA teima em gerar para o FTS não quebrar
var query_clean = (q.query_ilike || 'contrato');
query_clean = query_clean.replace(/["']/g, '');

var wb = $('Normalizar Input').first().json;
return [{ json: {
  query_ilike: query_clean,
  termos:      q.termos      || [],
  confidence:  q.confidence  || 0.5,
  domain:      q.domain      || '',
  titulo:      wb.titulo,
  problema:    wb.problema,
  descricao:   wb.descricao,
  user:        wb.user,
  parecer_id:  wb.parecer_id
}}];

var resultados = $input.all();
var qn = $('Formatar Query').first().json;
var docs = [];
if (resultados && resultados.length > 0) {
  if (resultados.length === 1 && Array.isArray(resultados[0].json)) {
    docs = resultados[0].json;
  } else {
    docs = resultados.map(item => item.json).filter(doc => Object.keys(doc).length > 0);
  }
}

function stripHtml(html) {
  if (!html) return '';
  return html.replace(/<[^>]*>?/gm, ' ').replace(/\s+/g, ' ').trim();
}

// Extrai o número de citação correto do TCU a partir do HTML bruto (antes de strip)
// O número real aparece no HTML: "Acórdão 1.301/2013", "Acórdão 1301/2013", etc.
function extrairNumeroCitacao(htmlBruto, orgao, dataPub) {
  var texto = htmlBruto || '';

  // Padrão: "Acórdão 1.301/2013" ou "Acórdão 1301/2013" (com ou sem ponto nos milhares)
  var match = texto.match(/[Aa]c[oó]rd[aã]o\s+([\d\.]{1,7})\/(\d{4})/);
  if (match) {
    var num = match[1].replace('.', ''); // remove ponto de milhar
    return 'Acórdão ' + num + '/' + match[2] + ' – ' + (orgao || '');
  }

  // Padrão 2: "ACÓRDÃO Nº 1234/2023"
  var match2 = texto.match(/ACÓRDÃO\s+N[ºo°]?\s*([\d\.]{1,7})\/(\d{4})/i);
  if (match2) {
    var num2 = match2[1].replace('.', '');
    return 'Acórdão ' + num2 + '/' + match2[2] + ' – ' + (orgao || '');
  }

  // Padrão 3: número no campo numero (ex: JURISPRUDENCIA-SELECIONADA-62707 → usa o ID numérico com orgao e ano)
  var ano = dataPub ? dataPub.substring(0, 4) : 's/d';
  var orgaoLabel = orgao || 'TCU';

  // Para jurisprudência selecionada, boletim, súmula: usar o próprio ID como referência
  return '[Precedente – ' + orgaoLabel + ' (' + ano + ')]';
}

var contexto = docs.slice(0, 12).map(function(doc, i) {
  var htmlEmenta  = doc.ementa   || '';
  var htmlSnippet = doc.snippet  || '';
  var htmlExcerto = doc.excerto  || '';
  var orgao       = doc.orgao    || '';
  var dataPub     = doc.data_pub || '';
  var tipo        = doc.tipo     || '';
  var numero      = doc.numero   || '';

  // Tenta extrair do HTML original (antes do strip)
  var citacao = extrairNumeroCitacao(htmlEmenta + ' ' + htmlSnippet, orgao, dataPub);

  // Agora faz o strip para texto limpo
  var ementa  = stripHtml(htmlEmenta).substring(0, 400);
  var snippet = stripHtml(htmlSnippet).substring(0, 350);
  var excerto = stripHtml(htmlExcerto).substring(0, 400);

  var conteudoPrincipal = excerto || ementa || snippet || 'Sem conteúdo disponível';

  var res = '[' + (i+1) + '] ' + citacao + '\n';
  res += 'Tipo: ' + tipo + '\n';
  if (ementa) res += 'Ementa: ' + ementa + '\n';
  if (snippet && snippet !== ementa) res += 'Trecho: ' + snippet;
  return res;
}).join('\n\n---\n\n');

return [{ json: {
  problema:                qn.problema,
  titulo:                  qn.titulo,
  descricao:               qn.descricao,
  user:                    qn.user,
  parecer_id:              qn.parecer_id,
  termos_buscados:         qn.termos,
  total_encontrado:        docs.length,
  contexto_jurisprudencia: contexto
}}];

var r = $input.first().json;
var parecer = r.text || r.output || (r.content && r.content[0] && r.content[0].text) || JSON.stringify(r);
return [{ json: { output: parecer } }];
